INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 'Getting Through Hard Seasons', 'Pillar: Emotional Well-being  ·  Sub-mode: General Emotional  ·  6 Sessions  ·  Classification: Capacity Erosion · Alignment Fracture  ·  No flag required', 'free', 'emotional', 'general', 6, 'Capacity Erosion · Alignment Fracture', 'enrollment:onboarding; flag:None — available to all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ff199e57-67ec-580e-a13c-9732f1e28955', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 1, 'Understanding what hard seasons actually are Session 1', 'Hard seasons don''t announce themselves. They tend to arrive gradually — you just notice one day that everything feels heavier than it used to. The things that used to restore you aren''t restoring you. The pace you used to sustain feels impossible. And somewhere underneath all of it is a quiet voice wondering if something is wrong with you. Nothing is wrong with you. You are in a hard season. That is different. A hard season is a period where the load exceeds the capacity. It is not a character flaw, a weakness, or a sign that you are falling apart. It is a signal — from your body, your nervous system, your life — that something needs to change. The season is telling you something. The first step is simply learning to hear it. Most people in hard seasons do one of two things. They push through — keeping the same pace, telling themselves they just need to work harder or rest better or get themselves together. Or they shut down — withdrawing, avoiding, going through the motions without actually being present. Neither of these works. There is a third option. It does not require you to have it figured out. It just requires you to be honest about where you actually are. That is where we start.', 'This week: notice one moment when you push through something instead of acknowledging it. Just notice. You don''t have to change it yet — just see it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('865793eb-a25f-5dff-9e29-70ddab40c250', 'ff199e57-67ec-580e-a13c-9732f1e28955', 1, 'When you think about the past few weeks, what has felt the heaviest? Name it as specifically as you can.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f7f5690e-9127-5edb-a6e2-88fd7d7be526', 'ff199e57-67ec-580e-a13c-9732f1e28955', 2, 'What have you been telling yourself about why you''re struggling — what story are you running about yourself right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('574e95ca-966f-55bb-8257-59f7365e7921', 'ff199e57-67ec-580e-a13c-9732f1e28955', 3, 'What is one thing you wish someone understood about what you''re carrying?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('3ccfdeb3-4652-548b-a0dc-2849fda4d07e', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 2, 'Permission to slow down without falling apart Session 2', 'There is a difference between slowing down and stopping. Between rest and collapse. Between allowing yourself to be in a hard season and giving up on yourself. Most people in hard seasons are afraid that if they slow down, everything will fall apart. The work won''t get done. The people depending on them will notice. They''ll fall so far behind they can''t catch up. So they keep the pace even when the pace is destroying them. Here is what is actually true: the pace you are keeping right now is already costing you more than you are getting from it. The slowdown has already started — it is just happening in ways you can''t fully see yet. Your sleep, your patience, your clarity, your energy — these are already affected. Slowing down deliberately is not giving in. It is choosing when and how the adjustment happens, rather than waiting for your body or your life to make the choice for you. Slowing down does not mean everything stops. It means deciding what actually has to happen and what can wait. It means protecting one thing — just one — that restores you. It means dropping the performance of being fine and being honest about what you actually have to give right now. You are allowed to do less. That is not failure. That is survival. And survival, right now, is the goal.', 'This week: identify one thing from your list that you can do less of — not permanently, just this week. Do it less. Notice what happens.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('dec117b9-3aac-5ff8-9734-d65374f42dd9', '3ccfdeb3-4652-548b-a0dc-2849fda4d07e', 1, 'What are you most afraid will happen if you slow down?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('954a62f8-fd27-58ff-af29-d7634ed0461e', '3ccfdeb3-4652-548b-a0dc-2849fda4d07e', 2, 'If you were advising a close friend in exactly your situation, what would you tell them they''re allowed to let go of right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fd477130-f507-5107-a935-7a115c8c5000', '3ccfdeb3-4652-548b-a0dc-2849fda4d07e', 3, 'What is one thing you are currently doing that is costing more than it is giving?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9b949f2c-bd68-570f-99ad-9f074135189d', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 3, 'The minimum viable day — what actually matters right now Session 3', 'When everything feels like too much, the question is not how to do everything. The question is what actually has to happen. Most people, when overwhelmed, have a list of obligations that they treat as equally urgent. Everything on the list feels important because everything on the list is real. But not everything on the list has the same consequence if it doesn''t happen. Some things, if they don''t happen today, will create real problems. Most things, if they don''t happen today, will still be there tomorrow. The minimum viable day is the version of your day that keeps the most important things going without requiring you to perform at a level you currently cannot sustain. It is not a lazy day. It is a realistic day. It is a day designed by someone who knows what they actually have to give, rather than designed by the aspirational version of themselves who ignores what they feel. To find your minimum viable day, you need to be honest about two things: what genuinely cannot wait, and what you have been treating as essential that is actually optional. Most people, when they do this honestly, find that the non-negotiable list is shorter than they thought. And the relief that comes from that recognition is real.', 'This week: write your minimum viable day for tomorrow. Just tomorrow. Three things that have to happen, and permission to leave the rest.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('219298f0-c45e-5cbd-9b25-60d5342b1a38', '9b949f2c-bd68-570f-99ad-9f074135189d', 1, 'List three things that genuinely cannot go undone this week — the ones where skipping them creates real consequences.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a4f86d3e-ae23-56d4-8b37-1439d4ee7aa6', '9b949f2c-bd68-570f-99ad-9f074135189d', 2, 'List three things you''ve been treating as essential but could probably wait, be delegated, or be dropped entirely.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a3c03286-8b80-5391-bc02-d9597a7bcfc2', '9b949f2c-bd68-570f-99ad-9f074135189d', 3, 'What does a realistic day look like for you right now — not ideal, not aspirational, just genuinely doable?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('75ccf166-657f-511a-80f2-cd71bb15881e', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 4, 'Finding one small anchor in the chaos Session 4', 'When everything is unstable, the impulse is to try to stabilize everything at once. That impulse is understandable. It is also part of why hard seasons feel so relentless — the scale of what needs to be different makes any single step feel inadequate. The anchor principle is the opposite of that. Instead of trying to stabilize everything, you identify one thing — one practice, one rhythm, one commitment — that you can hold even when everything else is shifting. Not because one thing will fix everything. But because one reliable thing in an unreliable period changes the felt experience of the season. The anchor can be small. It should be small. A walk at the same time every morning. Making your bed. Eating something real before noon. Calling one person. Going to bed before midnight. The specific thing matters less than the reliability. The anchor works because it is something you do when you feel like doing it and when you don''t. Its value is in the consistency, not in the content. When you have an anchor, you have evidence — physical, repeated evidence — that you can do something. That might sound like nothing. In a hard season, it is everything.', 'This week: choose your anchor. One small thing. Do it every day this week regardless of how you feel. Report back.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6ccd092b-255b-5181-8226-59edadf34063', '75ccf166-657f-511a-80f2-cd71bb15881e', 1, 'What is one thing you have managed to keep going even through this difficult period — something small that you have not completely let go of?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('754a3962-effa-58af-86b6-cb6709c98a96', '75ccf166-657f-511a-80f2-cd71bb15881e', 2, 'What is one small practice that, when you do it consistently, makes everything else feel slightly more manageable?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a1f4ad89-c13b-5994-950e-f95c15973276', '75ccf166-657f-511a-80f2-cd71bb15881e', 3, 'What would you need to make that practice non-negotiable this week — what would have to be true?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('7a7ead6c-1847-5bef-89e1-e33bc292ecce', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 5, 'Reaching out without feeling like a burden Session 5', 'One of the most common experiences of hard seasons is isolation. Not always external isolation — plenty of people in hard seasons are surrounded by others. But an internal isolation. The sense that what you are carrying is yours alone to carry. That telling someone would burden them, worry them, or change how they see you. This belief is almost always wrong. And it is costing you more than you know. The people who love you — or who care about you, or who would want to know — are generally not as fragile as you are treating them. They can hold what you are carrying if you give them the chance. What they cannot do is help with something they don''t know exists. Your silence is not protecting them. In most cases, it is just protecting you from the vulnerability of being known. Reaching out does not require you to have the words perfectly. It does not require you to know what you need. It can be as simple as: I''ve been having a hard time and I wanted to tell you that. That is it. You don''t have to ask for anything. You don''t have to explain everything. Just break the isolation. That is enough.', 'This week: reach out to one person. It can be a text. It can be three sentences. Just break the isolation once.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5498e7bc-37fd-5728-a293-d2045d7f1078', '7a7ead6c-1847-5bef-89e1-e33bc292ecce', 1, 'Who in your life would genuinely want to know that you are having a hard time right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ad27eebc-7e94-5b45-822a-4af9c6c4124f', '7a7ead6c-1847-5bef-89e1-e33bc292ecce', 2, 'What stops you from reaching out to them — what is the specific fear or concern?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7f6b298f-cdec-5745-97c9-adc5b30e64fa', '7a7ead6c-1847-5bef-89e1-e33bc292ecce', 3, 'What is the smallest version of reaching out that feels possible — not the full conversation, just the first move?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('45009548-7a71-58ad-9da9-2616f3f26066', 'fd060ad2-064d-5c57-82bb-92d0dcba3dd2', 6, 'What forward looks like when you''re depleted Session 6', 'Forward does not always look like progress. In a hard season, forward can look like maintaining. Like not losing more ground. Like keeping one thing going. Like getting through the day and being slightly more honest about how you feel. These count. The trap of hard seasons is that people measure forward against the version of themselves that existed before the season started. They compare current output to peak output. Current energy to peak energy. And by that measure, they are always failing. They are always behind. They are always not enough. The more useful measure is: compared to where I was at the lowest point of this hard season, what is different? What am I doing now that I couldn''t do then? What has held? What has slowly gotten easier? What have I learned about myself in this period that I didn''t know before? Hard seasons end. Most of them. And when they do, something is usually different — not just in your circumstances but in you. Not because hard seasons are good. They aren''t always. But because surviving something genuinely difficult changes you, whether you choose it or not. The question is whether you let it change you in a direction you would choose. You made it through this path. That is not nothing.', 'Closing commitment — no action required: You made it through this path. Before your next coaching session, take five minutes to write down one thing you are proud of from this hard season. It doesn''t have to be big. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1d5b00ad-0f43-5e03-b9f4-18d3f5500416', '45009548-7a71-58ad-9da9-2616f3f26066', 1, 'Looking back at the past few weeks since you started this path — what is one thing that feels even slightly different?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('bc6a80ba-5a71-5b95-8fa2-5648d4bab4e4', '45009548-7a71-58ad-9da9-2616f3f26066', 2, 'What have you learned about yourself during this hard season that you didn''t know before, or didn''t believe before?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('996c6dd4-886c-5d6d-b8af-c3ebcc2765e7', '45009548-7a71-58ad-9da9-2616f3f26066', 3, 'What is the one thing you most want to carry forward from this period into whatever comes next?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 'Burnout Recovery', 'Pillar: Professional  ·  Sub-mode: Stress and Burnout  ·  6 Sessions  ·  Classification: Capacity Erosion · High Output/Hidden Instability  ·  No flag required', 'free', 'professional', 'stress_burnout', 6, 'Capacity Erosion · High Output/Hidden Instability', 'enrollment:onboarding; flag:None');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e3fb4e4d-f09d-5696-b35a-f9b492c4df3b', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 1, 'Naming what happened — burnout, not weakness, not failure Session 1', 'Burnout is not a personal failing. It is what happens when output exceeds input for long enough that the system can no longer compensate. You did not burn out because you are weak. You burned out because you kept giving when there was less and less to give from. Because you prioritized output over restoration. Because the demands were real and you met them — until you couldn''t anymore. That is not a character flaw. That is a system responding rationally to an unsustainable condition. The word burnout is important. Not exhaustion, not stress, not a rough patch, not needing a vacation. Burnout. Burnout is different in degree and in what it requires to recover from. Exhaustion improves with sleep. Burnout requires a more significant recalibration — of pace, of expectations, of what you ask of yourself and what you protect. Naming it accurately matters because the wrong name leads to the wrong response. If you call it exhaustion, you take a weekend off and go back to the same pace. If you call it burnout, you understand that something has to actually change.', 'This week: do not add anything new. Do not start a new project, a new habit, or a new commitment. The only goal this week is to not make it worse.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2a24b660-912b-52f7-8c26-e5fa86a64144', 'e3fb4e4d-f09d-5696-b35a-f9b492c4df3b', 1, 'In your own words, what happened? Not the events — the internal experience of the past weeks or months.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8db94b12-e5ae-50ec-9fb9-a6f1b18e4f35', 'e3fb4e4d-f09d-5696-b35a-f9b492c4df3b', 2, 'What kept you going past the point where you should have slowed down? What made stopping feel impossible or wrong?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e4e3e76e-7dd0-5f1a-bdb4-bd1d59c85cb8', 'e3fb4e4d-f09d-5696-b35a-f9b492c4df3b', 3, 'What word would you use to describe where you are right now — and does burnout feel accurate?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('41101983-f03e-5854-bb45-ec64b1f1b42a', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 2, 'What your body and mind need right now Session 2', 'Recovery from burnout is not primarily a mental exercise. It is a physical and neurological process. Your body has been running in a state of chronic stress, and that has real physiological effects — on your sleep, your immune function, your hormones, your ability to concentrate, your emotional regulation. Recovery requires attending to these things, not just deciding to feel better. The sequence matters. Before you can rebuild anything, you need to stop the depletion. Before you can stop the depletion, you need to understand what is depleting you. Before you can make sustainable changes, your nervous system needs enough safety to actually regulate. This means that in early burnout recovery, the most important things are often the most basic: sleep, food, movement, reduced stimulation, time without demands. Not because these things are a cure, but because without them the conditions for recovery do not exist. You cannot think your way out of burnout. You can only create the conditions for your system to recover. The goal this week is not to fix anything. The goal is to give your body and nervous system something it has not had enough of: rest that is actually restful.', 'This week: protect one hour. One hour where there are no demands on you — no phone, no email, no tasks, no performance. Just one hour.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ca343f64-2152-55bf-b7e9-478060bba96a', '41101983-f03e-5854-bb45-ec64b1f1b42a', 1, 'How is your sleep right now — not what you think it should be, but what is actually happening?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4cca85db-3613-5733-9196-43c40f650e03', '41101983-f03e-5854-bb45-ec64b1f1b42a', 2, 'What does your body feel like right now, physically? Where are you holding tension, heaviness, or numbness?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2ae26012-f07c-5914-b020-f65cff02ea79', '41101983-f03e-5854-bb45-ec64b1f1b42a', 3, 'What does genuine rest look like for you — not passive consumption, but actually restorative? When did you last have that?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('4353d4be-f1c3-5a0d-ae64-ca01e6d52bdc', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 3, 'Removing one thing — just one Session 3', 'The instinct when burned out is often to reorganize everything. To build a new system, find a new approach, restructure the whole schedule. This instinct is understandable and it is counterproductive. Reorganizing everything requires the kind of executive function, clarity, and energy that burnout takes from you. Trying to redesign your life when you are running on empty tends to produce either nothing — the planning never converts to action — or a new system that collapses quickly because the underlying depletion has not been addressed. The more useful approach is smaller and more specific. Not redesigning everything. Removing one thing. One thing that is costing more than it is giving. One obligation that you have been carrying not because it is essential but because you have not yet given yourself permission to put it down. One thing that, if it stopped being your responsibility this week, would create even a small amount of relief. One thing. Not ten things. Not a restructuring. One concrete removal.', 'This week: remove or significantly reduce one thing from your load. It does not have to be permanent. Just this week. Tell one person what you are doing and why.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('96471759-344f-5b4c-b694-b9a9c2d8e2ad', '4353d4be-f1c3-5a0d-ae64-ca01e6d52bdc', 1, 'What is the one thing in your current load that is costing the most and giving the least?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('98e6a471-ffec-5b12-8448-bf651c004969', '4353d4be-f1c3-5a0d-ae64-ca01e6d52bdc', 2, 'What would you have to believe — about yourself, about others, about the consequences — to allow yourself to remove it or reduce it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('892d6217-be35-5c25-945e-c829a8d9b1aa', '4353d4be-f1c3-5a0d-ae64-ca01e6d52bdc', 3, 'What is the smallest possible reduction that would still feel like relief?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('4b76140a-d1ca-59e6-a99b-f36ce2b4200e', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 4, 'The minimum viable workday during recovery Session 4', 'There is a version of your workday that keeps the most important things going without requiring more than you currently have. Finding it requires honesty about two things: what genuinely cannot wait, and what you have been treating as essential that could actually wait or be delegated. During burnout recovery, the minimum viable workday is not a lazy day or a half-effort day. It is a realistic day. It is what happens when you design your day around your actual capacity rather than your aspirational capacity or the expectations you have absorbed from others. For most people in burnout recovery, the minimum viable workday is shorter than they think. The most important work — the work that actually cannot wait, that only they can do, that has real consequences — usually takes three to four focused hours. The rest of the time is often spent managing the appearance of productivity, catching up on things that have lower urgency than they feel, and responding to demands that feel urgent but aren''t actually critical. This is not permission to disappear. It is permission to be strategic about where your limited energy goes.', 'This week: design your minimum viable workday. Write it down. Try to live inside it for three days and notice what happens.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4048c52c-07a1-5e09-bcb4-4d4c3d59a538', '4b76140a-d1ca-59e6-a99b-f36ce2b4200e', 1, 'If you had to identify the three things in your workday that absolutely cannot be dropped or delegated, what are they?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1b7eb5c0-e9b7-5716-9c1e-89131948b261', '4b76140a-d1ca-59e6-a99b-f36ce2b4200e', 2, 'What are you currently doing at work that someone else could do, or that could wait until you have more capacity?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fde6185d-d4f5-59e5-ac22-318b16651bc7', '4b76140a-d1ca-59e6-a99b-f36ce2b4200e', 3, 'What would a realistic three-to-four hour focused workday look like for you right now — what would it include and what would it not include?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ba89b88f-429d-5d25-ae65-7921a5ba5807', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 5, 'What returning to normal should actually look like Session 5', 'Most people who burn out return to exactly the conditions that caused the burnout. They rest for a period, feel somewhat better, and then go back to the same pace, the same expectations, the same patterns — because the conditions that made burnout possible have not actually changed. This is why burnout recurs. Not because the person is weak, but because they treated the symptom rather than the cause. Returning to normal — or to something that functions — requires being honest about what normal was actually costing you. The pace that felt sustainable until it wasn''t. The expectations you met until you couldn''t. The way you had been treating your capacity as infinite when it was not. A genuine return involves not just recovering but recalibrating. It means deciding in advance what you are not willing to go back to, what structural changes need to happen before you re-enter, and what early warning signs you will pay attention to this time. Without this, recovery is just a pause before the next burnout.', 'This week: write down two things you will not go back to. Make it specific. Keep the list somewhere you will see it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1289d384-46a4-5135-bef3-c3362f3c95fc', 'ba89b88f-429d-5d25-ae65-7921a5ba5807', 1, 'What was the old normal like — honestly? Not the version you told people, but the actual daily experience of it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('05dc1bdd-9289-5ee1-ad9f-341966642ee8', 'ba89b88f-429d-5d25-ae65-7921a5ba5807', 2, 'What are you not willing to go back to? What has this experience made clear should not be part of your working life at this level?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('18b7a040-ce95-51e5-9181-515c8177294b', 'ba89b88f-429d-5d25-ae65-7921a5ba5807', 3, 'What would need to be different — structurally, not just in your mindset — for the return to be sustainable?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('17aa4766-f8b6-5aae-9720-5673f4f8ebc8', '23c1f8da-4f08-51c0-bcc0-e4ed845a5b7e', 6, 'Protecting yourself from the same pattern Session 6', 'Burnout is not a one-time event for most people who experience it. It is a pattern. And like all patterns, it has recognizable early signals — signals that showed up before the burnout was fully formed, that were visible in retrospect even when they were invisible in the moment. Learning to see those signals earlier — and taking them seriously before they become a crisis — is one of the most important things that can come from a burnout experience. Not the shame of having burned out, not the resolution to be stronger next time, but the specific knowledge of your personal early warning system. Your early warning signs are probably not dramatic. They tend to be small and easy to dismiss. The quality of your sleep starting to shift. The things that used to restore you stopping to work. A growing sense of dread before certain parts of your day. Increased irritability or emotional flatness. The feeling of performing normal when nothing feels normal. These signals are not problems. They are information. The difference between someone who burns out repeatedly and someone who breaks the pattern is often just whether they take the signals seriously before they become impossible to ignore.', 'Closing commitment: You completed this path. Write your personal early warning system — three specific signals that tell you burnout is building. Keep it somewhere you can find it. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9e2b4b8a-8386-5ba8-88fd-fdb8e58b6946', '17aa4766-f8b6-5aae-9720-5673f4f8ebc8', 1, 'Looking back, what were the early signals of this burnout that you noticed but either dismissed or pushed through?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2bf78c06-001e-50d2-b5ae-831be159b33d', '17aa4766-f8b6-5aae-9720-5673f4f8ebc8', 2, 'What would it mean to take those signals seriously if they appear again — what would you actually do differently?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f1147dc8-ed64-540e-9ab1-854d2826bdf5', '17aa4766-f8b6-5aae-9720-5673f4f8ebc8', 3, 'What is one structural change — to your schedule, your commitments, your environment, or your relationship with work — that would make it harder for this pattern to repeat?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('0fbcafdc-5c57-589b-afc1-50955c324ca9', 'Recovery Roadmap', 'Pillar: Health and Wellness  ·  Sub-mode: Recovery and Sobriety  ·  6 Sessions  ·  All classifications  ·  Requires recovery_mode_active \= yes', 'free', 'health', 'recovery', 6, 'All classifications — this path matches any classification', 'enrollment:onboarding; flag:recovery_mode_active \= yes — MANDATORY');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('c33469ac-dd08-5fa8-8067-07a89cf3f28f', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 1, 'You don''t have to have it all figured out right now Session 1', 'Recovery does not require that you have the whole picture figured out before you start. It doesn''t require that you know how you''ll handle every situation, what you''ll say to certain people, or how long this will take. It requires exactly one thing: that you keep going for the next small stretch of time. This is important because the full picture of recovery can feel overwhelming. When you look at everything that might need to change — relationships, environments, habits, identity — the scale of it can make any single step feel pointless. It can make starting feel impossible. It can make the whole thing feel like too much. So don''t look at the whole picture right now. Just look at today. Or if today is too much, just look at the next few hours. The requirement is not that you do everything. The requirement is that you do this — this session, this reflection, this one thing in front of you. You are here. That is not nothing. That is actually the only thing that has to be true right now.', 'This week: one day at a time. Your only commitment is to come back to this path for session 2\.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3b31c243-e20f-510e-858b-a5645e174452', 'c33469ac-dd08-5fa8-8067-07a89cf3f28f', 1, 'What brought you here today — not the whole story, just what made you take this step?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5e5f6b80-157d-5cad-abc0-d1aebd093639', 'c33469ac-dd08-5fa8-8067-07a89cf3f28f', 2, 'When you think about recovery, what feels most possible right now? What feels most impossible?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f14cb65e-c106-5584-a0f8-9c4545080165', 'c33469ac-dd08-5fa8-8067-07a89cf3f28f', 3, 'What does support look like for you — what kind of support actually helps versus what kind makes things harder?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('51bf3fc1-a60e-56d0-b23d-2918721cf9c8', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 2, 'What early recovery actually looks like Session 2', 'Early recovery is not what it looks like from the outside, or what people who haven''t experienced it assume it looks like. From the outside, it can look like someone who has stopped doing something and is now fine. From the inside, it feels different. Early recovery involves a body and nervous system that are recalibrating. It involves an emotional landscape that can shift significantly from hour to hour. It involves navigating situations, relationships, and internal states with tools that are still being developed. It is not a straight line. It is not consistent improvement. It is often two steps forward and one step back, or one step forward and standing still for a while. This is not failure. This is recovery. What looks like inconsistency from outside is actually the normal shape of how people heal from something that changed their brain chemistry and their relationship with themselves. The most important thing to know about early recovery is that it is a phase. Not a permanent state. The intensity of it — the cravings, the emotional variability, the difficulty of some moments — lessens over time for most people who stay with it. You will not always feel this new to it.', 'This week: track your difficult moments. Not to judge them — just to notice when they happen, how long they last, and what (if anything) helped them pass.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('71e99259-f0a5-5ad5-b109-840b2e13151b', '51bf3fc1-a60e-56d0-b23d-2918721cf9c8', 1, 'What has early recovery actually felt like for you — not what you expected, but the real experience?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('95afcd87-eb18-5e52-840c-325cef54842b', '51bf3fc1-a60e-56d0-b23d-2918721cf9c8', 2, 'What has been harder than you expected? What has been easier or different than you thought?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('51f97b15-ac98-5cb3-85dc-d42297a4bc01', '51bf3fc1-a60e-56d0-b23d-2918721cf9c8', 3, 'What is one thing that has helped, even slightly, in the moments that have been difficult?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('b131442b-3b30-5dc0-8e34-b2005b4d698d', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 3, 'Your one commitment for this week Session 3', 'Recovery works in small increments. Not because small things are all that matter, but because small things done consistently are what large things are built from. A commitment in recovery is different from a goal. A goal is something you achieve. A commitment is something you return to, even when you don''t achieve it perfectly. The distinction matters because in recovery, the measure is not perfection — it is continuation. Coming back after a hard day. Getting through the next hour. Returning to the commitment even when you slipped away from it. Your commitment for this week should be specific enough to be real and small enough to be honest. Not ''I will be in perfect recovery'' — that is not a commitment, it is a wish. Something like: I will check in on this path every day this week. I will call my sponsor when I feel like I might not make it. I will not be alone when I know I am in a high-risk moment. Something specific and yours. The point of the commitment is not to be perfect. It is to have something to return to when things are hard. A place to come back to.', 'Set your commitment: write it down. Tell one person. Come back to this path for session 4 this week.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('840df778-2d41-559e-ac71-48e4a26e3a12', 'b131442b-3b30-5dc0-8e34-b2005b4d698d', 1, 'What is the most important commitment you can make to your recovery this week — specific, honest, and yours?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9e609825-dae4-546e-b82b-f94a297c1538', 'b131442b-3b30-5dc0-8e34-b2005b4d698d', 2, 'What makes that commitment hard to keep? What are the specific moments or conditions where it is most at risk?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d7546395-abb1-55a6-b607-c299d5f5dc0f', 'b131442b-3b30-5dc0-8e34-b2005b4d698d', 3, 'Who, if anyone, knows about this commitment? And would telling someone make it more likely you would keep it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('cb44f56e-02b3-5ccc-b9b0-bb0ce0ca806d', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 4, 'When cravings hit — what to do in the moment Session 4', 'Cravings are not a sign that recovery is failing. They are a normal part of how the brain and body respond after changing a significant pattern. Understanding this matters because many people in recovery treat cravings as evidence that something is wrong with them — as weakness, as failure, as proof that they cannot do this. None of that is accurate. A craving is a brain signal. It is strong and it is real, but it is not permanent and it is not inevitable. Most cravings peak in intensity within 20 to 30 minutes and then subside, whether or not they are acted on. The feeling that the craving will never stop unless you act on it is a feature of cravings — it is not an accurate prediction. What helps in the moment is having a plan before the moment arrives. Not figuring out what to do when you are already in the middle of a craving — the cognitive resources available in that moment are limited. Having practiced responses ready before you need them is the difference between being swept along by the craving and having something to grab onto. The most effective craving responses are immediate, physical, and social. Move your body. Change your environment. Call someone. These are not complicated strategies. They work because they interrupt the cycle at the point where interruption is most possible.', 'Build your crisis plan: write down two things you will do when a craving hits, and one person you will call. Keep it somewhere accessible — your phone, your wallet, somewhere you can find it in the moment.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9f7f6504-2b53-5a4d-b98a-bccd5d73c30a', 'cb44f56e-02b3-5ccc-b9b0-bb0ce0ca806d', 1, 'What does a craving feel like for you — specifically, in your body and in your thoughts?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('df64f8a3-ef2d-5974-9bb4-2d4426c6c229', 'cb44f56e-02b3-5ccc-b9b0-bb0ce0ca806d', 2, 'What has helped you get through a craving in the past, even if just for long enough?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fcacab5f-4ebd-5cd5-96c6-7d841ab52a14', 'cb44f56e-02b3-5ccc-b9b0-bb0ce0ca806d', 3, 'Who can you call in the moment when a craving is strong? Do they know they are on that list?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('13ec5176-793f-5f20-b4b9-9d030913b93f', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 5, 'Who is on your support team Session 5', 'Recovery in isolation is significantly harder than recovery with support. This is not because people who attempt recovery alone are weaker or less committed — it is because human connection is one of the most powerful tools available in recovery, and going without it is like trying to build something without the most important material. Support in recovery does not look the same for everyone. For some people it is a formal program — AA, NA, SMART Recovery, or a similar community. For others it is a therapist, a sponsor, a counselor. For others it is a small number of people who know what is happening and who show up consistently. The form matters less than the fact of it — that someone knows, that someone is available, that you are not carrying this entirely alone. The honest question is not whether you have perfect support. Almost no one does. The honest question is whether the support you have is enough for where you are right now, and what would make it more adequate. Even one person who genuinely knows what you are going through and is on your side changes the experience of recovery.', 'This week: if there is someone who should know and doesn''t, reach out to one of them. It can be a text. It can be three sentences. You don''t have to explain everything.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5a814de4-fd2c-57ee-b720-4944e0734c78', '13ec5176-793f-5f20-b4b9-9d030913b93f', 1, 'Who currently knows about your recovery — who is aware of what you are working through?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('58d64a6c-c242-51ad-be56-2ba9b21aec0e', '13ec5176-793f-5f20-b4b9-9d030913b93f', 2, 'Of the people who know, who shows up in a way that actually helps? What do they do that makes the difference?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f1ad3866-9663-5206-9ed2-a98144078a51', '13ec5176-793f-5f20-b4b9-9d030913b93f', 3, 'Is there someone who doesn''t know yet who you think would be an important part of your support — and what would it take to tell them?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('57f9d98f-fcf6-5781-9b26-b5864eed7377', '0fbcafdc-5c57-589b-afc1-50955c324ca9', 6, 'The next 7 days — just the next 7 days Session 6', 'You made it through this path. That is worth saying clearly. Recovery does not require that you see the whole road ahead of you. It does not require that you have answers to every question, solutions to every challenge, or certainty about what comes next. It requires that you stay with it — one day, one decision, one moment at a time. The next seven days are what matter right now. Not the next seven months, not the next seven years. Seven days. You know from the sessions in this path what helps, what your risks are, who your support is, and what commitment you are holding. These are real tools. Not everything you will ever need, but real and usable for the next week. At the end of seven days, you will have more information — about what worked, what was harder than expected, what you still need. That information will shape what comes next. But you cannot get that information without going through the seven days. One day at a time is not a cliché. It is the actual strategy. The days add up.', 'Your commitment for the next 7 days: write it down. Read it every morning this week. That is the whole plan.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('01f60073-31e1-5779-9b9c-6a0ae7b6d302', '57f9d98f-fcf6-5781-9b26-b5864eed7377', 1, 'What do the next seven days require from you — what are the specific situations, people, or moments you will need to navigate?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('61dbb77f-e620-5711-9c23-f46bdc9661cc', '57f9d98f-fcf6-5781-9b26-b5864eed7377', 2, 'What will you do in the next seven days to support your recovery — specific, small, and honest?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a62e2373-dc4b-5e89-bd96-a20f1396757f', '57f9d98f-fcf6-5781-9b26-b5864eed7377', 3, 'What would it mean to you to look back at this week from the other side and know that you made it through?');
